class Auth {
  static const _kToken = 'access_token';

  // ✅ Wipe leftover Keychain on first launch (iOS reinstall hangover)
  Future<void> ensureFreshInstall(SharedPreferences prefs) async {
    if (prefs.getBool('first_run') != true) {
      await _storage.deleteAll();
      await prefs.setBool('first_run', true);
    }
  }

  Future<void> saveToken(String token) async {
    try {
      await _storage.write(key: _kToken, value: token);
    } on PlatformException catch (e) {
      // Possible causes: device just rebooted before unlock, biometric required
      log('secure write failed: $e');
      rethrow;
    }
  }

  Future<String?> readToken() async {
    try {
      return await _storage.read(key: _kToken);
    } on PlatformException {
      // Common on Android backup/restore — drop and re-auth
      await _storage.delete(key: _kToken);
      return null;
    }
  }
}

import 'dart:convert';
import 'dart:io';
import 'package:path/path.dart' as p;
import 'package:path_provider/path_provider.dart';

class NoteStore {
  Future<File> _fileFor(String id) async {
    final dir = await getApplicationDocumentsDirectory();
    final notes = Directory(p.join(dir.path, 'notes'));
    if (!await notes.exists()) await notes.create(recursive: true);
    return File(p.join(notes.path, '$id.json'));
  }

  Future<Note?> read(String id) async {
    final f = await _fileFor(id);
    if (!await f.exists()) return null;
    return Note.fromJson(jsonDecode(await f.readAsString()));
  }

  // Atomic-ish write — write to a temp file, then rename. Avoids corruption on crash.
  Future<void> write(Note note) async {
    final f = await _fileFor(note.id);
    final tmp = File('${f.path}.tmp');
    await tmp.writeAsString(jsonEncode(note.toJson()), flush: true);
    await tmp.rename(f.path);
  }

  Future<void> evictThumbnail(String id) async {
    // Use the OS's evictable cache for derived data
    final cache = await getTemporaryDirectory();
    final f = File(p.join(cache.path, 'thumb_$id.jpg'));
    if (await f.exists()) await f.delete();
  }
}

