@DriftDatabase(tables: [Tasks])
class AppDb extends _\$AppDb {
  AppDb(super.e);

  @override int get schemaVersion => 2;

  @override
  MigrationStrategy get migration => MigrationStrategy(
    onCreate: (m) => m.createAll(),
    onUpgrade: (m, from, to) async {
      if (from < 2) await m.addColumn(tasks, tasks.dueAt);
    },
  );

  // Reactive query — emits whenever the tasks table changes
  Stream<List<Task>> watchOpenTasks() =>
      (select(tasks)..where((t) => t.done.equals(false))).watch();

  // Type-safe insert
  Future<int> add(String title) =>
      into(tasks).insert(TasksCompanion.insert(title: title));

  // Update with named-arg builder
  Future<int> setDone(int id, bool done) =>
      (update(tasks)..where((t) => t.id.equals(id)))
          .write(TasksCompanion(done: Value(done)));
}

